import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest';
import { sortNotesByUpdatedAt } from './sortNotesByUpdatedAt';

describe('sortNotesByUpdatedAt', () => {
  it('should handle happy path: sort by updatedAt descending', () => {
    const notes = [
      { id: 1, updatedAt: new Date('2023-01-01') },
      { id: 2, updatedAt: new Date('2023-03-01') },
      { id: 3, updatedAt: new Date('2023-02-01') },
    ];
    const sorted = sortNotesByUpdatedAt(notes);
    expect(sorted.map(n => n.id)).toEqual([2, 3, 1]);
  });

  it('should handle edge case: notes with identical updatedAt', () => {
    const notes = [
      { id: 1, updatedAt: new Date('2023-01-01') },
      { id: 2, updatedAt: new Date('2023-01-01') },
      { id: 3, updatedAt: new Date('2023-01-01') },
    ];
    const sorted = sortNotesByUpdatedAt(notes);
    // order should remain as original if timestamps are equal
    expect(sorted.map(n => n.id)).toEqual([1, 2, 3]);
  });

  it('should handle null/empty: null, undefined, empty string, 0', () => {
    // null
    const sortedNull = sortNotesByUpdatedAt(null as unknown as any[]);
    expect(sortedNull).toEqual([]);

    // undefined
    const sortedUndefined = sortNotesByUpdatedAt(undefined as unknown as any[]);
    expect(sortedUndefined).toEqual([]);

    // empty string
    const sortedEmptyString = sortNotesByUpdatedAt('' as unknown as any[]);
    expect(sortedEmptyString).toEqual([]);

    // 0
    const sortedZero = sortNotesByUpdatedAt(0 as unknown as any[]);
    expect(sortedZero).toEqual([]);
  });
});

