import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest';
import { countWords } from './countWords';

describe('countWords', () => {
  beforeEach(() => {
    // No external dependencies to mock for this simple utility
  });

  afterEach(() => {
    vi.restoreAllMocks();
  });

  it('should handle happy path with a normal sentence', () => {
    const text = 'The quick brown fox jumps over the lazy dog';
    // Expected: 9 words
    expect(countWords(text)).toBe(9);
  });

  it('should handle edge case with extra whitespace and punctuation', () => {
    const text = '  Hello,   world!   This is a test...  ';
    // Expected words: "Hello", "world", "This", "is", "a", "test" => 6
    expect(countWords(text)).toBe(6);
  });

  it('should handle null/empty inputs gracefully', () => {
    // undefined
    expect(countWords(undefined as unknown as string)).toBe(0);
    // null
    expect(countWords(null as unknown as string)).toBe(0);
    // empty string
    expect(countWords('')).toBe(0);
    // numeric zero coerced to string
    expect(countWords(0 as unknown as string)).toBe(0);
  });
});